// Animate layer along a shape path using pointOnPath().
// Default fallback Easing: [0,0,1,1] (linear) if marker absent or invalid.
// Partial segments by %, loop/ping-pong, reverse direction.

var defaultDuration = 2;
var defaultEasing   = [0,0,1,1];  // always fallback to linear
var defaultSegment  = [0,100];    // entire path
var defaultLoop     = "none";   // no loop or ping-pong by default

// Reverse direction checkbox
var reverseDir = effect("Reverse Direction")("Checkbox") > 0;

function clamp(v, mn, mx){ return Math.min(Math.max(v, mn), mx); }

// Find marker with 'Animation' in the comment.
var markerData = null;
for(var mk=1; mk<=thisLayer.marker.numKeys; mk++){
  var mVal = thisLayer.marker.key(mk);
  if(mVal.comment && mVal.comment.indexOf("Animation") !== -1){
    markerData = mVal;
    break;
  }
}

var startTime = markerData ? markerData.time : inPoint;
var duration  = markerData ? (markerData.duration > 0 ? markerData.duration : defaultDuration) : defaultDuration;
var easing    = defaultEasing;
var segment   = defaultSegment;
var loopMode  = defaultLoop;

if(markerData){
  // parse marker comment, e.g. "Animation Easing: 0.42,0,0.58,1 || Segment 20 - 75% || Loop"
  var parts = markerData.comment.split("||");
  for(var i=0; i<parts.length; i++){ parts[i] = parts[i].replace(/^\s+|\s+$/g, ""); }

  // parse Easing
  var easeRE = /Easing:\s*([-+]?[0-9]*\.?[0-9]+),\s*([-+]?[0-9]*\.?[0-9]+),\s*([-+]?[0-9]*\.?[0-9]+),\s*([-+]?[0-9]*\.?[0-9]+)/;
  for(var e=0; e<parts.length; e++){
    if(parts[e].indexOf("Easing")!==-1){
      var m = parts[e].match(easeRE);
      if(m){
        easing = [ parseFloat(m[1]), parseFloat(m[2]), parseFloat(m[3]), parseFloat(m[4]) ];
      }
      break;
    }
  }

  // parse Segment by percentage
  var segRE = /Segment\s+([0-9]+\.?[0-9]*)%?\s*-\s*([0-9]+\.?[0-9]*)%/i;
  for(var s=0; s<parts.length; s++){
    if(parts[s].indexOf("Segment")!==-1){
      var pm = parts[s].match(segRE);
      if(pm){
        segment = [ parseFloat(pm[1]), parseFloat(pm[2]) ];
      }
      break;
    }
  }

  // parse Loop / PingPong
  for(var l=0; l<parts.length; l++){
    if(/loop/i.test(parts[l])){
      loopMode = "loop";
    } else if(/ping\s*-?\s*pong/i.test(parts[l])){
      loopMode = "pingpong";
    }
  }
}

// Cubic Bezier function
function cubicBezier(t, p1x,p1y, p2x,p2y){
  function bz(tt, p0,p1,p2,p3){
    var c=3*(p1-p0);
    var b=3*(p2-p1)-c;
    var a=1-c-b;
    return ((a*tt+b)*tt + c)*tt + p0;
  }
  function getTForX(x, eps){
    var guess=x;
    for(var i=0;i<10;i++){
      var xEst = bz(guess, 0,p1x,p2x,1);
      var dx   = (bz(guess+eps, 0,p1x,p2x,1)-xEst)/eps;
      if(Math.abs(xEst-x)<eps) return guess;
      guess -= (xEst-x)/dx;
    }
    return guess;
  }
  var eps=1e-5;
  var solved=getTForX(t, eps);
  return bz(solved, 0, p1y,p2y,1);
}

// Loop/pingpong
function getLoopedProgress(tm, st, dur, mode){
  var locT = tm - st;
  function cl(v){return clamp(v,0,1);} // shorthand

  if(mode==='none'){
    return cl(locT/dur);
  } else if(mode==='loop'){
    if(dur<=0) return 0;
    var mv = locT%dur; if(mv<0) mv+=dur;
    return cl(mv/dur);
  } else if(mode==='pingpong'){
    if(dur<=0) return 0;
    var cycle=2*dur;
    var mv2= locT%cycle; if(mv2<0) mv2+=cycle;
    if(mv2<=dur){
      return cl(mv2/dur);
    } else {
      return cl(1 - ((mv2-dur)/dur));
    }
  }
  return 0;
}

// 1) raw progress
var rawP = getLoopedProgress(time, startTime, duration, loopMode);
// 2) eased
var eased = cubicBezier(rawP, easing[0], easing[1], easing[2], easing[3]);
// 3) reverse?
var finalP = reverseDir ? 1 - eased : eased;

// 4) partial by %
var segStart = clamp(segment[0], 0, 100)/100;
var segEnd   = clamp(segment[1], 0, 100)/100;
if(segEnd<segStart){ var tmp=segStart; segStart=segEnd; segEnd=tmp; }
var subP = linear(finalP, 0,1, segStart, segEnd);

// 5) pointOnPath(subP)
// We'll call .toComp() on the actual shape layer:
var shapeLayer = thisComp.layer("Path Shape");
var thePath    = thisComp.layer("Path Shape")("Contents")("Group 1")("Path 1")("Path");
var pathPos    = thePath.pointOnPath(subP); // local coords
var compPos    = shapeLayer.toComp(pathPos);

// if this layer is parented, fromComp
if(thisLayer.hasParent){
  compPos = parent.fromComp(compPos);
}

compPos; // done.
